// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_node_runtime_lifecycle_3(configured: boolean, dependencyReady: boolean, draining: boolean): { phase: string; admit: boolean } {
  let phase = configured ? "starting" : "configuration-failed";
  let admit = configured && dependencyReady && !draining;
  if (admit) phase = "ready";
  if (draining) {
    phase = "draining";
    admit = false;
  }
  return { phase, admit };
}

